{
  "files": [
    {"path": "README.md", "content": "# Project Management API

This is a simple project management API built with Node.js and Express.
It includes endpoints for managing projects, tasks, members, and comments."},
    {"path": "package.json", "content": "{ "name": "project-management-api", "version": "1.0.0", "main": "src/app.js", "scripts": { "start": "node src/server.js" }, "dependencies": { "express": "^4.17.1", "crypto": "^1.0.0" } }"},
    {"path": "src/app.js", "content": "const express = require('express');
const app = express();
const projectsRouter = require('./modules/projects/routes');
const membersRouter = require('./modules/members/routes');
const tasksRouter = require('./modules/tasks/routes');
const commentsRouter = require('./modules/comments/routes');
app.use(express.json());
app.get('/health', (req, res) => { res.json({ ok: true }); });
app.use('/projects', projectsRouter);
app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRouter);
module.exports = app;"},
    {"path": "src/server.js", "content": "const app = require('./app');
const port = process.env.PORT || 3000;
app.listen(port, () => { console.log(`Server running on port ${port}`); });"},
    {"path": "src/modules/projects/routes.js", "content": "const express = require('express');
const router = express.Router();
const { createProject } = require('./service');
router.post('/', (req, res) => { const project = createProject(req.body); if (!project) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Invalid input' } }); res.status(201).json(project); });
module.exports = router;"},
    {"path": "src/modules/projects/service.js", "content": "const { randomUUID } = require('crypto');
const projects = [];
const createProject = (data) => {
  if (!data.name) return null;
  const project = { id: randomUUID(), ...data };
  projects.push(project);
  return project;
};
module.exports = { createProject };"},
    {"path": "src/modules/members/routes.js", "content": "const express = require('express');
const router = express.Router();
const { addMember } = require('./service');
router.post('/', (req, res) => { const member = addMember(req.body); if (!member) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Invalid input' } }); if (projects.some(p => p.id === req.params.projectId && p.members.includes(member))) return res.status(409).json({ error: { code: 'DUPLICATE_MEMBER', message: 'Member already exists for this project' } }); res.status(201).json(member); });
module.exports = router;"},
    {"path": "src/modules/members/service.js", "content": "const { randomUUID } = require('crypto');
const addMember = (data) => {
  if (!data.userId || !data.role) return null;
  const member = { id: randomUUID(), ...data };
  return member;
};
module.exports = { addMember };"},
    {"path": "src/modules/tasks/routes.js", "content": "const express = require('express');
const router = express.Router();
const { createTask } = require('./service');
router.post('/', (req, res) => { const task = createTask(req.body); if (!task) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Invalid input' } }); res.status(201).json(task); });
module.exports = router;"},
    {"path": "src/modules/tasks/service.js", "content": "const { randomUUID } = require('crypto');
const tasks = [];
const createTask = (data) => {
  if (!data.title) return null;
  const task = { id: randomUUID(), ...data };
  taskspush.(task);
  return task;
};
module.exports = { createTask };"},
    {"path": "src/modules/comments/routes.js", "content": "const express = require('express');
const router = express.Router();
const { addComment } = require('./service');
router.post('/', (req, res) => { const comment = addComment(req.body); if (!comment) return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Invalid input' } }); res.status(201).json(comment); });
module.exports = router;"},
    {"path": "src/modules/comments/service.js", "content": "const { randomUUID } = require('crypto');
const addComment = (data) => {
  if (!data.message) return null;
  const comment = { id: randomUUID(), ...data };
  return comment;
};
module.exports = { addComment };"},
    {"path": "src/lib/errors.js", "content": "class CustomError extends Error {
  constructor(code, message) {
    super(message);
    this.code = code;
  }
}
module.exports = { CustomError };"},
